targets.expr:
max(
  label_replace(
    kube_node_status_condition{condition="Ready", status="true"} 
    * on(node) group_left(label_alias, label_node_role) 
    kube_node_labels,
    
    # [수정] 정규표현식 대신, 우리가 붙인 label_alias를 display_name으로 바로 복사합니다.
    "display_name", "$1", "label_alias", "(.+)"
  )
) by (display_name)

count by (display_name) (
  label_replace(
    kube_pod_info{pod=~"web-nginx.*"} 
    * on(node) group_left(label_alias) 
    kube_node_labels,
    
    # [수정] 노드 라벨(ip-10-0-...) 대신 우리가 박은 alias(k3s-web-01)를 그대로 사용
    "display_name", "$1", "label_alias", "(.+)"
  )
)

(
  # 1. 쿠버네티스 노드들 처리 (라벨링 적용)
  100 * (
    1 - (
      avg by (display_name) (
        label_replace(
          (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes)
          # [핵심] 조인을 위해 instance 라벨 형식을 맞추는 복잡한 로직은 유지
          * on(instance) group_left(label_alias) 
          label_replace(
            label_replace(kube_node_labels, "instance", "$1.$2.$3.$4:9100", "node", "ip-([0-9]+)-([0-9]+)-([0-9]+)-([0-9]+)"),
            "instance", "$1:9100", "node", "^(([0-9]+\\.){3}[0-9]+)$"
          ),
          
          # [수정] 조인된 label_alias를 display_name으로 바로 사용
          "display_name", "$1", "label_alias", "(.+)"
        )
      )
    )
  )
)
OR
(
  # 2. 모니터링 서버 처리 (외부 노드)
  100 * (
    1 - (
      avg by (display_name) (
        label_replace(
          (node_memory_MemAvailable_bytes{instance=~"host.docker.internal.*"} / node_memory_MemTotal_bytes{instance=~"host.docker.internal.*"}),
          "display_name", "monitoring", "instance", "(.*)"
        )
      )
    )
  )
)
